+		}
+
+		const lines = child.split("\n");
+		if (lines.length === 1) {
+			return child;
+		}
+
+		return lines.map((line, index) => (
+			<Fragment key={index}>
+				{index > 0 ? <br /> : null}
+				{line}
+			</Fragment>
+		));
+	});
+}

